import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { auth, db } from '../firebase';
import { doc, getDoc, setDoc } from 'firebase/firestore';

const JOBS = [
  'Warlock', 'Wizard', 'Hunter', 'Assassin', 'Knight',
  'Crusader', 'Priest', 'Monk', 'Bard', 'Dancer',
  'Blacksmith', 'Alchemist', 'Rogue', 'Sage'
];

const ROLES = ['DPS', 'Support', 'Tank'];

function Profile() {
  const [charName, setCharName] = useState('');
  const [job, setJob] = useState('');
  const [role, setRole] = useState('');
  const [saved, setSaved] = useState(false);
  const navigate = useNavigate();
  const user = auth.currentUser;

  useEffect(() => {
    const fetchProfile = async () => {
      const ref = doc(db, 'users', user.uid);
      const snap = await getDoc(ref);
      if (snap.exists()) {
        const data = snap.data();
        setCharName(data.charName || '');
        setJob(data.job || '');
        setRole(data.role || '');
      }
    };
    fetchProfile();
  }, [user]);

  const handleSave = async () => {
    const ref = doc(db, 'users', user.uid);
    await setDoc(ref, {
      charName,
      job,
      role,
      email: user.email,
      displayName: user.displayName,
      uid: user.uid
    });
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <div style={{ backgroundColor: '#1a1a2e', minHeight: '100vh', color: 'white', padding: '20px' }}>
      <button onClick={() => navigate('/')} style={btnStyle('#555')}>← Torna alla Home</button>
      <h2 style={{ marginTop: '20px' }}>👤 Il tuo profilo personaggio</h2>

      <div style={{ maxWidth: '400px', marginTop: '30px' }}>
        <label>Nome personaggio</label>
        <input
          value={charName}
          onChange={e => setCharName(e.target.value)}
          placeholder="Es. JohnWarlock"
          style={inputStyle}
        />

        <label>Job</label>
        <select value={job} onChange={e => setJob(e.target.value)} style={inputStyle}>
          <option value="">-- Seleziona job --</option>
          {JOBS.map(j => <option key={j} value={j}>{j}</option>)}
        </select>

        <label>Ruolo</label>
        <select value={role} onChange={e => setRole(e.target.value)} style={inputStyle}>
          <option value="">-- Seleziona ruolo --</option>
          {ROLES.map(r => <option key={r} value={r}>{r}</option>)}
        </select>

        <button onClick={handleSave} style={btnStyle('#2ecc71')}>
          💾 Salva profilo
        </button>

        {saved && <p style={{ color: '#2ecc71', marginTop: '10px' }}>✅ Profilo salvato!</p>}
      </div>
    </div>
  );
}

const inputStyle = {
  display: 'block',
  width: '100%',
  padding: '10px',
  marginTop: '5px',
  marginBottom: '20px',
  borderRadius: '6px',
  border: 'none',
  backgroundColor: '#16213e',
  color: 'white',
  fontSize: '1rem'
};

const btnStyle = (color) => ({
  padding: '10px 20px',
  backgroundColor: color,
  color: 'white',
  border: 'none',
  borderRadius: '6px',
  cursor: 'pointer',
  fontSize: '1rem'
});

export default Profile;
